// Combinar resultados de los 4 detectores
const duplicados = $('Detector: Duplicados (A6)').all();
const sinSoporte = $('Detector: Sin Soporte (A7)').all();
const patron = $('Detector: Patrón Sistemático (A11)').all();
const fuga = $('Detector: Fuga Silenciosa (A12)').all();

const todas = [...duplicados, ...sinSoporte, ...patron, ...fuga];

if (todas.length === 0) return [{ json: { sin_alertas: true } }];

return todas.map(item => ({ json: { ...item.json } }));

