// Combinar alerta con respuesta de IA
const alertaData = $('Combinar Resultados Detectores').item.json;
const iaResponse = $input.first().json;

let iaJson = {};
try {
  // Intentar parsear la respuesta JSON de Gemini
  const text = iaResponse.content || iaResponse.text || iaResponse.message || '';
  const match = text.match(/\{[\s\S]*\}/);
  if (match) iaJson = JSON.parse(match[0]);
} catch(e) {}

return [{
  json: {
    ...alertaData,
    causa_raiz_sugerida: iaJson.causa_raiz || 'Clasificación pendiente',
    narrativa_ia: iaJson.narrativa || alertaData.narrativa_corta,
    borrador_comunicacion: iaJson.borrador_comunicacion || null
  }
}];

